const crypto = require('crypto');
const webhookBody = $('Webhook Trigger').first().json.body;
const headers = $('Webhook Trigger').first().json.headers;
const secret = $('Workflow Constants').first().json.N8N_SHARED_SECRET;

const signature = headers['x-profunda-signature'];
if (!signature) throw new Error('Missing x-profunda-signature header');
if (!webhookBody || typeof webhookBody !== 'object') throw new Error('Missing or invalid webhook body');
if (webhookBody.workflow_key !== 'watchlist_ingest') throw new Error('workflow_key must be watchlist_ingest');
if (!webhookBody.run_id) throw new Error('Missing run_id');

const bodyStr = JSON.stringify(webhookBody);
const hmac = crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');
if (hmac !== signature) throw new Error('Invalid HMAC signature');

return [{ json: webhookBody }];

const input = $('Verify Signature').first().json;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!input.org_id || typeof input.org_id !== 'string' || !UUID_RE.test(input.org_id)) {
  throw new Error('org_id must be a valid UUID');
}

let website_url = input.website_url || null;
if (website_url && typeof website_url === 'string') {
  website_url = website_url.trim();
  if (!/^https?:\/\//i.test(website_url)) website_url = 'https://' + website_url;
}

return [{
  json: {
    run_id: input.run_id,
    workflow_key: 'watchlist_ingest',
    org_id: input.org_id,
    org_name: input.org_name || null,
    website_url
  }
}];

const validated = $('Validate Input').first().json;
const url = validated.website_url;

if (!url) {
  return [{ json: { run_id: validated.run_id, org_id: validated.org_id, crawl_skipped: true, skip_reason: 'No website URL provided' } }];
}

return [{ json: { run_id: validated.run_id, org_id: validated.org_id, org_name: validated.org_name, website_url: url, crawl_skipped: false } }];

const resolveData = $('Resolve URL').first().json;
const run_id = resolveData.run_id;
const org_id = resolveData.org_id;
const crypto = require('crypto');

if (resolveData.crawl_skipped) {
  return [{ json: { run_id, org_id, snapshot: null, facts: [], content_hash: null, crawl_skipped: true } }];
}

let scrapeData;
try { scrapeData = $('Firecrawl Scrape').first().json; } catch (e) {
  return [{ json: { run_id, org_id, snapshot: null, facts: [], content_hash: null, crawl_error: 'Firecrawl error: ' + String(e.message).slice(0, 200) } }];
}

if (scrapeData.error || !scrapeData.success) {
  return [{ json: { run_id, org_id, snapshot: null, facts: [], content_hash: null, crawl_error: scrapeData.error || 'Unsuccessful' } }];
}

const markdown = scrapeData.data?.markdown || '';
const metadata = scrapeData.data?.metadata || {};
const links = scrapeData.data?.links || [];

const content_hash = crypto.createHash('sha256').update(markdown).digest('hex');

// Build snapshot
const snapshot = {
  title: (metadata.title || '').slice(0, 200),
  description: (metadata.description || '').slice(0, 500),
  content_length: markdown.length,
  links_count: links.length,
  source_url: metadata.sourceURL || resolveData.website_url,
  scraped_at: new Date().toISOString()
};

// Extract basic facts
const facts = [];
const contentLower = markdown.toLowerCase();
const sectors = ['education', 'healthcare', 'housing', 'technology', 'nonprofit', 'government'];
for (const sector of sectors) {
  if (contentLower.includes(sector)) facts.push({ fact_type: 'sector', value: sector });
}

return [{ json: { run_id, org_id, snapshot, facts, content_hash, crawl_error: null } }];

const validated = $('Validate Input').first().json;
let data = null;
let error = null;
let failed_node = null;

try { data = $('Build Snapshot').first().json; } catch (e1) {
  try { data = $('Skip Crawl').first().json; } catch (e2) {
    error = 'No output from snapshot or skip';
    failed_node = 'Build Snapshot';
  }
}

if (data && data.crawl_error) { error = data.crawl_error; failed_node = 'Firecrawl Scrape'; }

let result = null;
if (!error && data) {
  result = { org_id: data.org_id, snapshot: data.snapshot, facts: data.facts || [], content_hash: data.content_hash, crawl_skipped: data.crawl_skipped || false };
}

return [{ json: { run_id: validated.run_id, workflow_key: 'watchlist_ingest', payload: { result, error, failed_node } } }];
